import { useState, useEffect } from 'react';
import { useParams } from 'react-router-dom';
import { Helmet } from 'react-helmet-async';

// Import all section components
import Benefits from '../components/sections/Benefits';
import Features from '../components/sections/Features';
import Pricing from '../components/sections/Pricing';
import Steps from '../components/sections/Steps';
import FAQ from '../components/sections/FAQ';
import FinalCTA from '../components/sections/FinalCTA';
import Testimonials from '../components/sections/Testimonials';
import Contact from '../components/sections/Contact';
import TextImage from '../components/sections/TextImage';
import Gallery from '../components/sections/Gallery';

import api from '../services/api';

// Section type to component mapping
const SECTION_COMPONENTS = {
  hero: null, // Inline rendering
  benefits: Benefits,
  features: Features,
  pricing: Pricing,
  steps: Steps,
  faq: FAQ,
  cta: FinalCTA,
  testimonials: Testimonials,
  contact: Contact,
  text_image: TextImage,
  gallery: Gallery,
  default: null, // Default inline rendering
  custom: null,
};

// Hero Section Renderer (inline as it needs special styling)
function renderHeroSection(section) {
  const { title, subtitle, content, buttonText, buttonLink, button2Text, button2Link, backgroundColor, textColor } = section;

  const style = {};
  if (backgroundColor) {
    if (backgroundColor.startsWith('#')) {
      style.backgroundColor = backgroundColor;
    } else if (backgroundColor.startsWith('bg-')) {
      style.backgroundColor = `var(--${backgroundColor})`;
    }
  }
  if (textColor) {
    style.color = textColor;
  }

  return (
    <section 
      className="py-16 md:py-24 bg-yellow-500 text-white"
      style={backgroundColor ? { backgroundColor } : undefined}
    >
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 text-center">
        {title && (
          <h1 className="text-4xl md:text-5xl font-bold mb-6">{title}</h1>
        )}
        {subtitle && (
          <p className="text-xl md:text-2xl text-yellow-100 mb-4">{subtitle}</p>
        )}
        {content && (
          <p className="text-lg text-yellow-50 mb-8 max-w-2xl mx-auto">{content}</p>
        )}
        <div className="flex flex-col sm:flex-row gap-4 justify-center">
          {buttonText && buttonLink && (
            <a
              href={buttonLink}
              className="bg-white text-yellow-600 px-8 py-3 rounded-lg font-semibold hover:bg-yellow-50 transition-colors"
            >
              {buttonText}
            </a>
          )}
          {button2Text && button2Link && (
            <a
              href={button2Link}
              className="border-2 border-white text-white px-8 py-3 rounded-lg font-semibold hover:bg-white/10 transition-colors"
            >
              {button2Text}
            </a>
          )}
        </div>
      </div>
    </section>
  );
}

// Default/Custom Section Renderer with cards
function renderDefaultSection(section) {
  const { 
    title, subtitle, content, image, buttonText, buttonLink, 
    button2Text, button2Link, backgroundColor, textColor, cards 
  } = section;

  const sectionStyle = {};
  if (backgroundColor) {
    if (backgroundColor.startsWith('#')) {
      sectionStyle.backgroundColor = backgroundColor;
    } else {
      sectionStyle.backgroundColor = `var(--${backgroundColor})`;
    }
  }
  if (textColor) {
    sectionStyle.color = textColor;
  }

  return (
    <section 
      className="py-12 md:py-16 bg-white"
      style={Object.keys(sectionStyle).length > 0 ? sectionStyle : undefined}
    >
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        {title && (
          <h2 className="text-3xl md:text-4xl font-bold mb-4 text-gray-800">
            {title}
          </h2>
        )}
        {subtitle && (
          <p className="text-xl text-gray-600 mb-6">{subtitle}</p>
        )}
        {content && (
          <div 
            className="prose max-w-none text-gray-600 mb-8"
            dangerouslySetInnerHTML={{ __html: content }}
          />
        )}

        {image && (
          <img
            src={image}
            alt={title || 'Image'}
            className="rounded-xl shadow-lg mb-8 w-full h-auto max-w-2xl"
          />
        )}

        {/* Buttons */}
        {(buttonText || button2Text) && (
          <div className="flex flex-wrap gap-4 mb-8">
            {buttonText && buttonLink && (
              <a
                href={buttonLink}
                className="bg-yellow-500 text-white px-6 py-3 rounded-lg font-medium hover:bg-yellow-600"
              >
                {buttonText}
              </a>
            )}
            {button2Text && button2Link && (
              <a
                href={button2Link}
                className="border-2 border-yellow-500 text-yellow-600 px-6 py-3 rounded-lg font-medium hover:bg-yellow-50"
              >
                {button2Text}
              </a>
            )}
          </div>
        )}

        {/* Cards */}
        {cards && cards.length > 0 && (
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
            {cards.map((card) => (
              <div key={card.id} className="bg-gray-50 rounded-xl p-6 hover:shadow-md transition-shadow">
                {card.icon && (
                  <i className={`fas ${card.icon} text-2xl text-yellow-500 mb-3`}></i>
                )}
                {card.image && (
                  <img 
                    src={card.image} 
                    alt={card.title} 
                    className="w-full h-40 object-cover rounded-lg mb-3"
                  />
                )}
                {card.title && (
                  <h3 className="text-xl font-semibold text-gray-800 mb-2">
                    {card.title}
                  </h3>
                )}
                {card.description && (
                  <p className="text-gray-600">{card.description}</p>
                )}
                {card.content && !card.description && (
                  <p className="text-gray-600">{card.content}</p>
                )}
              </div>
            ))}
          </div>
        )}
      </div>
    </section>
  );
}

export default function DynamicPage() {
  const { slug } = useParams();
  const [page, setPage] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  useEffect(() => {
    if (!slug) {
      setError('No slug provided');
      setLoading(false);
      return;
    }

    setLoading(true);

    // Fetch page by slug
    api.get(`/pages/${slug}`)
      .then(res => res.data)
      .then(pageData => {
        console.log('Page data:', pageData);
        if (pageData && (pageData.slug || pageData.id)) {
          setPage(pageData);
        } else if (pageData && pageData.error) {
          setError(pageData.error);
        } else {
          setError('Page not found');
        }
        setLoading(false);
      })
      .catch(err => {
        console.error('API Error:', err.response || err);
        const errorMsg = err.response?.data?.error || err.message || 'Cannot connect to API';
        setError(errorMsg);
        setLoading(false);
      });
  }, [slug]);

  // Render a single section based on its type
  const renderSection = (section, index) => {
    if (!section.isEnabled) return null;

    const sectionType = section.type || 'default';

    // Hero section - special inline rendering
    if (sectionType === 'hero') {
      return <div key={section.id || index}>{renderHeroSection(section)}</div>;
    }

    // Check if there's a specific component for this type
    const Component = SECTION_COMPONENTS[sectionType];
    if (Component) {
      return <Component key={section.id || index} section={section} />;
    }

    // Default fallback: render with cards
    return <div key={section.id || index}>{renderDefaultSection(section)}</div>;
  };

  if (loading) {
    return (
      <div className="min-h-screen flex items-center justify-center">
        <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-yellow-500"></div>
      </div>
    );
  }

  if (error || !page) {
    return (
      <div className="min-h-screen flex items-center justify-center">
        <div className="text-center">
          <h1 className="text-2xl font-bold text-gray-800 mb-2">Page non trouvée</h1>
          <p className="text-gray-600">{error || 'Cette page n\'existe pas ou n\'est pas publiée.'}</p>
        </div>
      </div>
    );
  }

  // Sort sections by position
  const sortedSections = [...(page.sections || [])].sort((a, b) => a.position - b.position);

  return (
    <div className="min-h-screen bg-white">
      <Helmet>
        <title>{page.metaTitle || page.title || 'Page'}</title>
        {page.metaDescription && <meta name="description" content={page.metaDescription} />}
      </Helmet>

      {/* Render sorted sections */}
      {sortedSections.map((section, index) => renderSection(section, index))}
    </div>
  );
}
